/** Reusable Academic Management page renderer. */
function sms_academic_count(array $items, string $field, string $value): int { return count(array_filter($items, fn($item) => (string)($item[$field] ?? '') === $value)); }
function sms_academic_render_cards(array $cards): void { echo '<section class="row g-3 mb-4">'; foreach ($cards as $card) { echo '<div class="col-sm-6 col-xl-3">'; sms_render_component('statistics-card', $card); echo '</div>'; } echo '</section>'; }
function sms_academic_render_page(array $config): void {
    $items = $config['items']; $columns = $config['columns']; $fields = $config['fields']; $actions = $config['actions'] ?? ['Edit','Delete'];
?>
<?php require_once(__DIR__ . '/academic-module-styles.php'); ?>
<div class="admin-academic-module">
    <section class="module-hero"><div class="breadcrumb-line">Dashboard <i class="fa-solid fa-angle-right mx-1"></i> Academic Management <i class="fa-solid fa-angle-right mx-1"></i> <?php echo sms_e($config['title']); ?></div><div class="d-flex align-items-center justify-content-between flex-wrap gap-3"><div><span class="module-kicker"><i class="<?php echo sms_e($config['icon']); ?>"></i> <?php echo sms_e($config['title']); ?></span><h3 class="mt-3 mb-2"><?php echo sms_e($config['heading']); ?></h3><p class="text-muted mb-0"><?php echo sms_e($config['description']); ?></p></div><button class="module-btn btn-primary-soft" data-bs-toggle="modal" data-bs-target="#academicFormModal" type="button"><i class="fa-solid fa-plus"></i> Add New</button></div></section>
    <?php sms_academic_render_cards($config['cards']); ?>
    <section class="module-card"><h4>Search & Filter</h4><form id="academicFilterForm"><div class="filter-grid"><div><label>Name</label><input class="form-control" id="nameFilter" placeholder="Search by name"></div><div><label>Status</label><select class="form-select" id="statusFilter"><option value="">All Statuses</option><option>Active</option><option>Inactive</option><option>Completed</option><option>Upcoming</option><option>Scheduled</option></select></div><div><label><?php echo sms_e($config['filter_label'] ?? 'Category'); ?></label><input class="form-control" id="extraFilter" placeholder="Optional filter"></div><div class="d-flex align-items-end gap-2"><button class="module-btn btn-primary-soft" type="submit">Search</button><button class="module-btn btn-muted-soft" type="reset">Reset Filters</button></div></div></form></section>
