e="Delete" data-name="<?php echo sms_e($item['name'] ?? $item['title'] ?? 'record'); ?>" data-bs-toggle="modal" data-bs-target="#deleteAcademicModal"><i class="fa-solid fa-trash"></i></button></div></td></tr><?php endforeach; ?></tbody></table></div><div class="d-flex justify-content-between align-items-center flex-wrap gap-2 pt-3"><div class="d-flex align-items-center gap-2"><span class="text-muted fw-bold">Records per page</span><select class="form-select" style="width:90px"><option>10</option><option>25</option><option>50</option><option>100</option></select></div><div class="d-flex gap-2"><a class="module-btn btn-muted-soft" href="#">Previous</a><a class="module-btn btn-primary-soft" href="#">1</a><a class="module-btn btn-muted-soft" href="#">Next</a></div></div></section>
    <div class="modal fade" id="academicFormModal" tabindex="-1"><div class="modal-dialog modal-dialog-centered modal-lg"><form class="modal-content" id="academicEntityForm" method="post" action="<?php echo sms_e($config['controller']); ?>"><div class="modal-header"><h5 class="modal-title">Add / Edit <?php echo sms_e($config['entity']); ?></h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="id" value=""><div class="form-grid"><?php foreach ($fields as $field): ?><div class="<?php echo !empty($field['full']) ? 'full' : ''; ?>"><label><?php echo sms_e($field['label']); ?></label><?php if (($field['type'] ?? 'text') === 'select'): ?><select class="form-select" name="<?php echo sms_e($field['name']); ?>"><?php foreach ($field['options'] as $option): ?><option><?php echo sms_e($option); ?></option><?php endforeach; ?></select><?php elseif (($field['type'] ?? 'text') === 'textarea'): ?><textarea class="form-control" name="<?php echo sms_e($field['name']); ?>"></textarea><?php else: ?><input class="form-control" type="<?php echo sms_e($field['type'] ?? 'text'); ?>" name="<?php echo sms_e($field['name']); ?>" <?php echo !empty($field['required']) ? 'required' : ''; ?>><?php endif; ?></div><?php endforeach; ?></div></div><div class="modal-footer"><button class="module-btn btn-muted-soft" type="reset">Reset</button><button class="module-btn btn-muted-soft" type="button" data-bs-dismiss="modal">Cancel</button><button class="module-btn btn-primary-soft" type="submit">Save</button></div></form></div></div>
    <div class="modal fade" id="deleteAcademicModal" tabindex="-1"><div class="modal-dialog modal-dialog-centered"><form class="modal-content" id="deleteAcademicForm" method="post" action="<?php echo sms_e($config['delete_controller']); ?>"><div class="modal-header"><h5 class="modal-title">Delete <?php echo sms_e($config['entity']); ?></h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><p>Are you sure you want to delete this record?</p><p class="text-muted fw-bold">This should become a soft delete with audit logging during backend integration.</p><strong id="deleteRecordName">Selected record</strong></div><div class="modal-footer"><button class="module-btn btn-muted-soft" type="button" data-bs-dismiss="modal">Cancel</button><button class="module-btn btn-danger-soft" type="submit">Delete</button></div></form></div></div>
</div></div></div>
<script>/* Shared Academic Management frontend behavior. */(function(){var rows=[].slice.call(document.querySelectorAll('#academicTable tbody tr'));academicFilterForm.onsubmit=function(e){e.preventDefault();var n=nameFilter.value.toLowerCase(),s=statusFilter.value;rows.forEach(function(r){r.style.display=(!n||r.dataset.name.indexOf(n)>-1)&&(!s||r.dataset.status===s)?'':'none';});};academicFilterForm.onreset=function(){setTimeout(function(){rows.forEach(function(r){r.style.display='';});},0)};selectAllRows.onchange=function(){document.querySelectorAll('.row-check').forEach(function(c){c.checked=selectAllRows.checked;});};deleteSelected.onclick=function(){var c=document.querySelectorAll('.row-check:checked').length;if(!c){alert('Please select at least one record.');return;}alert(c+' record(s) marked for deletion.');};exportCsv.onclick=function(){alert('CSV export placeholder ready for backend integration.');};exportExcel.onclick=function(){alert('Excel export placeholder ready for backend integration.');};printList.onclick=function(){window.print();};document.querySelectorAll('.delete-row').forEach(function(b){b.onclick=function(){deleteRecordName.textContent=b.dataset.name||'Selected record';};});document.querySelectorAll('.activate-row').forEach(function(b){b.onclick=function(){alert('Activation placeholder: backend should ensure only one active session/term where applicable.');};});academicEntityForm.onsubmit=function(e){e.preventDefault();if(!this.checkValidity()){this.reportValidity();return;}alert('Record saved. Future endpoint: '+this.action);};deleteAcademicForm.onsubmit=function(e){e.preventDefault();alert('Record soft-deleted. Future endpoint: '+this.action);};})();</script>
<?php } ?>